class Solution {
    public long maximumOr(int[] nums, int k) {
        long ans = 0;
        for (int num : nums) {
            ans |= num;
        }
        long max = ans;
        for (int i = 0; i < nums.length; i++) {
            long temp = ans;
            int cnt = 0;
            int num = nums[i];
            while (cnt <= k && (temp ^ (temp | num)) != 0) {
                temp |= num;
                num <<= 1;
                cnt++;
            }
            max = Math.max(max, temp);
        }
        return max;
    }
}
